from fastapi import FastAPI, status
from pydantic import BaseModel, Field

app = FastAPI()

class ProductCreate(BaseModel):
    name: str = Field(description='Tên sản phẩm cần thêm', examples=['Bàn phím cơ mechanical'])
    price: float = Field(description='Giá bán sản phẩm', examples=[49.99])
    stock: int = Field(default=10, description='Số lượng tồn kho ban đầu', examples=[50])

@app.post(
    '/products/',
    response_model=ProductCreate,
    status_code=status.HTTP_201_CREATED,
    summary='Thêm sản phẩm mới',
    description='Gửi thông tin sản phẩm từ Client để tạo một sản phẩm mới trong hệ thống MySQL.',
    tags=['products'],
    responses={
        201: {'description': 'Sản phẩm được tạo thành công trong MySQL'},
        400: {'description': 'Dữ liệu đầu vào không hợp lệ hoặc thiếu thông tin bắt buộc'}
    }
)
def create_product(product: ProductCreate):
    return product

