from typing import Optional
from fastapi import FastAPI, Path, Query
from pydantic import BaseModel

app = FastAPI()

class ProductSchema(BaseModel):
    name: str
    price: float
    in_stock: bool = True

# Endpoint kết hợp Path Parameter và Query Parameter
@app.get("/products/{product_id}")
async def get_product(
    product_id: int = Path(..., title="ID sản phẩm", ge=1),
    category: Optional[str] = Query(None, description="Lọc theo danh mục")
):
    return {"product_id": product_id, "category": category}

# Endpoint POST tiếp nhận dữ liệu từ Request Body
@app.post("/products/", status_code=201)
async def create_product(product: ProductSchema):
    return {"message": "Thêm mới sản phẩm thành công", "data": product}

